void solve(int[] queens, int row, int n, List<int[]> solutions) {
    if (row == n) { solutions.add(queens.clone()); return; }
    for (int col = 0; col < n; col++) {
        if (isValid(queens, row, col)) {
            queens[row] = col;
            solve(queens, row + 1, n, solutions);
        }
    }
}
